
IF  EXISTS (SELECT * FROM sys.objects WHERE object_id = OBJECT_ID(N'[ACTIVEMQ_MSGS]') AND type in (N'U'))
DROP TABLE [ACTIVEMQ_MSGS]
GO

CREATE TABLE ACTIVEMQ_MSGS
(ID INTEGER NOT NULL
, CONTAINER VARCHAR(250)
, MSGID_PROD VARCHAR(250)
, MSGID_SEQ INTEGER
, EXPIRATION BIGINT
, MSG VarBinary(max) , 
PRIMARY KEY ( ID ) ) 

GO

CREATE INDEX ACTIVEMQ_MSGS_MIDX ON ACTIVEMQ_MSGS (MSGID_PROD,MSGID_SEQ) 
GO

CREATE INDEX ACTIVEMQ_MSGS_CIDX ON ACTIVEMQ_MSGS (CONTAINER)
GO

CREATE INDEX ACTIVEMQ_MSGS_EIDX ON ACTIVEMQ_MSGS (EXPIRATION)
GO

GRANT DELETE ON [dbo].[ACTIVEMQ_MSGS] TO [IMNET] AS [dbo]
GO
GRANT INSERT ON [dbo].[ACTIVEMQ_MSGS] TO [IMNET] AS [dbo]
GO
GRANT SELECT ON [dbo].[ACTIVEMQ_MSGS] TO [IMNET] AS [dbo]
GO
GRANT UPDATE ON [dbo].[ACTIVEMQ_MSGS] TO [IMNET] AS [dbo]
